import express from 'express';
import path from 'path';

const app = express();

// Serve static frontend from /public
app.use(express.static(path.join(__dirname, '..', 'public')));

// Simple API endpoint for tests and future use
app.get('/api/hello', (_req, res) => {
  res.json({ message: 'Hello World' });
});

// Fallback: serve index.html (static will handle it but keep for clarity)
app.get('/', (_req, res) => {
  res.sendFile(path.join(__dirname, '..', 'public', 'index.html'));
});

export default app;

// If run directly, start the server
if (require.main === module) {
  const port = process.env.PORT || 3000;
  app.listen(port, () => {
    // eslint-disable-next-line no-console
    console.log(`Server listening on http://localhost:${port}`);
  });
}

import request from 'supertest';
import app from '../src/index';

describe('Basic server', () => {
  it('GET / should return 200 and contain Hello', async () => {
    const res = await request(app).get('/');
    expect(res.status).toBe(200);
    expect(res.text).toMatch(/Hello World/);
  });

  it('GET /api/hello should return JSON with message', async () => {
    const res = await request(app).get('/api/hello');
    expect(res.status).toBe(200);
    expect(res.body).toEqual({ message: 'Hello World' });
  });
});
